Here are pytest‑style unit tests in plain text (no Markdown formatting). You can put them into a test file such as test_retry.py.

from retry_module import retry  # adjust import as needed
import pytest

def test_retry_happy_path_first_try():
    def fn():
        return "ok"
    assert retry(fn) == "ok"

def test_retry_happy_path_succeeds_after_retries():
    calls = {"count": 0}
    def fn():
        calls["count"] += 1
        if calls["count"] < 3:
            raise ValueError("fail")
        return "success"
    assert retry(fn, max_attempts=5) == "success"
    assert calls["count"] == 3

def test_retry_raises_after_max_attempts():
    def fn():
        raise RuntimeError("always fails")
    with pytest.raises(RuntimeError):
        retry(fn, max_attempts=3)

def test_retry_zero_attempts():
    # edge case: max_attempts = 0 means loop never runs, so fn never called
    # This should immediately return None because no return is executed.
    def fn():
        raise AssertionError("fn should never be called")
    result = retry(fn, max_attempts=0)
    assert result is None

def test_retry_fn_returns_none_is_valid():
    def fn():
        return None
    assert retry(fn, max_attempts=3) is None

def test_retry_does_not_swallow_non_final_exceptions():
    # Ensure exceptions prior to last attempt are swallowed
    # and not re-raised.
    calls = {"count": 0}
    def fn():
        calls["count"] += 1
        if calls["count"] == 1:
            raise ValueError("temp fail")
        return "ok"
    assert retry(fn, max_attempts=3) == "ok"
    assert calls["count"] == 2
